wire clk_mid;
wire domain_sig;
Bar bar_inst (.clk(clk_mid));
Baz baz_inst (.domain_out(domain_sig), .clk_out(clk_mid));

module Baz (
  output ClockDomain B,
  output clock domains [B] out
);

wire w1, w2;
assign w2 = w1;
Bar bar (.clk(w1));
Baz baz (.out(w2));
assign w2 = baz.out;

domain ClockDomain;

Bar bar (.clk(net)); // inferred domain depends on baz.B
Baz baz (.B(domain), .out(net));

Baz baz(
  .B   (domain_out),
  .out (baz_clk)  // belongs to domain of port B
);

wire clk_wire;
wire clk_wire_0;
assign clk_wire_0 = clk_wire;
Bar bar(.clk(clk_wire));
assign clk_wire_0 = baz_out;

Bar bar(.clk(wire));
Baz baz(
  .B(domain),
  .out(out)  // inferred domain exported by baz.B
);
